+    pub fn build(self) -> ApiResponse<T> {
+        let success = self.data.is_some();
+        ApiResponse {
+            api_version: API_VERSION,
+            timestamp: current_timestamp(),
+            request_id: self.request_id,
+            command: self.command,
+            success,
+            data: self.data,
+            error: self.error,
+        }
+    }
